svg.script:
//
(function() {
  var svg  = document.getElementById('root');
  var ns   = 'http://www.w3.org/2000/svg';
  var R    = 210;
  var PUSH = 14;

  var slices = [
    { id:'sl1', pathId:'sp1', light:'s1',   dark:'s1d'   },
    { id:'sl2', pathId:'sp2', light:'s2',   dark:'s2d'   },
    { id:'sl3', pathId:'sp3', light:'s3',   dark:'s3d'   },
    { id:'sl4', pathId:'sp4', light:'s4',   dark:'s4d'   },
    { id:'sl5', pathId:'sp5', light:'s5',   dark:'s5d'   },
    { id:'sl6', pathId:'sp6', light:'s6',   dark:'s6d'   },
    { id:'sl7', pathId:'sp7', light:'s7',   dark:'s7d'   },
    { id:'sl8', pathId:'sp8', light:'s8',   dark:'s8d'   },
    { id:'sl9', pathId:'sp9', light:'soth', dark:'sothd' },
  ];

  function swapColors(dark) {
    slices.forEach(function(s) {
      var p = document.getElementById(s.pathId);
      if (p) p.setAttribute('fill', 'url(#' + (dark ? s.dark : s.light) + ')');
    });
  }

  function setMode(wantDark) {
    var currently = svg.classList.contains('dark');
    if (wantDark === currently) return;
    var thumb = document.getElementById('tthumb');
    var lbl   = document.getElementById('tlabel');
    if (wantDark) {
      svg.classList.add('dark');
      if (thumb) thumb.setAttribute('cx', '52');
      if (lbl)   lbl.textContent = 'Light';
    } else {
      svg.classList.remove('dark');
      if (thumb) thumb.setAttribute('cx', '16');
      if (lbl)   lbl.textContent = 'Dark';
    }
    swapColors(wantDark);
  }

  document.getElementById('dark-toggle').addEventListener('click', function() {
    setMode(!svg.classList.contains('dark'));
  });
  document.getElementById('print-toggle').addEventListener('click', function() {
    var thumb = document.getElementById('pthumb'), lbl = document.getElementById('plabel');
    if (svg.classList.toggle('print')) { thumb.setAttribute('cx','52'); lbl.textContent='Screen'; }
    else                               { thumb.setAttribute('cx','16'); lbl.textContent='Print';  }
  });

  var tipLayer = document.getElementById('tip-layer');
  var tipMap   = {};

  function el(tag, attrs) {
    var e = document.createElementNS(ns, tag);
    Object.keys(attrs).forEach(function(k){ e.setAttribute(k, attrs[k]); });
    return e;
  }

  svg.querySelectorAll('.slice-g').forEach(function(g) {
    var sliceId  = g.id;
    var midDeg   = parseFloat(g.getAttribute('data-mid'));
    var label    = g.getAttribute('data-label');
    var val      = g.getAttribute('data-val');
    var pct      = g.getAttribute('data-pct');
    var midRad   = midDeg * Math.PI / 180;
    var dx = Math.cos(midRad);
    var dy = Math.sin(midRad);
    var cx = 310, cy = 330;
    var bw = Math.max(90, label.length * 7 + 30);
    var bh = 56, hw = bw / 2, hh = bh / 2, TAIL = 14;
    var tipX = cx + dx * R;
    var tipY = cy + dy * R;
    var bCx = tipX, bCy = tipY - hh - TAIL;
    if (bCx - hw < 8)    bCx = 8 + hw;
    if (bCx + hw > 1092) bCx = 1092 - hw;
    if (bCy - hh < 8)    bCy = 8 + hh;
    var baseY = bCy + hh;

    var tipG = el('g', { 'class':'tip', 'data-for':sliceId });
    tipLayer.appendChild(tipG);
    tipMap[sliceId] = tipG;

    /* No filter — flat design */
    tipG.appendChild(el('rect', { x:(bCx-hw).toFixed(1), y:(bCy-hh).toFixed(1),
      width:bw, height:bh, rx:9, 'class':'bub-bg' }));
    tipG.appendChild(el('rect', { x:(bCx-hw).toFixed(1), y:(bCy-hh).toFixed(1),
      width:bw, height:bh, rx:9, 'class':'bub-bdr' }));
    tipG.appendChild(el('polygon', {
      points:(bCx-10)+','+(baseY-1)+' '+(bCx+10)+','+(baseY-1)+' '+bCx+','+tipY,
      'class':'bub-tip-poly' }));
    tipG.appendChild(el('path', {
      d:'M'+(bCx-10)+','+(baseY-1)+' '+bCx+','+tipY+' '+(bCx+10)+','+(baseY-1),
      'class':'bub-bdr', fill:'none', 'stroke-width':'1' }));

    var tv = el('text', { x:bCx.toFixed(1), y:(bCy-10).toFixed(1),
      'text-anchor':'middle', 'dominant-baseline':'central', 'class':'bub-val' });
    tv.textContent = val;
    tipG.appendChild(tv);
    var tl = el('text', { x:bCx.toFixed(1), y:(bCy+5).toFixed(1),
      'text-anchor':'middle', 'dominant-baseline':'central', 'class':'bub-lbl' });
    tl.textContent = label;
    tipG.appendChild(tl);
    var tp = el('text', { x:bCx.toFixed(1), y:(bCy+18).toFixed(1),
      'text-anchor':'middle', 'dominant-baseline':'central', 'class':'bub-pct' });
    tp.textContent = pct;
    tipG.appendChild(tp);

    var pushTx = 'translate(' + (dx*PUSH).toFixed(1) + ',' + (dy*PUSH).toFixed(1) + ')';
    var pushX  = dx * PUSH, pushY = dy * PUSH;
    var sliceData = slices.filter(function(s){ return s.id === sliceId; })[0];

    g.addEventListener('mouseenter', function() {
      var p = document.getElementById(sliceData.pathId);
      if (p) p.setAttribute('transform', pushTx);
      tipMap[sliceId].style.opacity = '1';
      tipMap[sliceId].setAttribute('transform',
        'translate(' + pushX.toFixed(1) + ',' + pushY.toFixed(1) + ')');
    });
    g.addEventListener('mouseleave', function() {
      var p = document.getElementById(sliceData.pathId);
      if (p) p.removeAttribute('transform');
      tipMap[sliceId].style.opacity = '';
      tipMap[sliceId].removeAttribute('transform');
    });
  });

  /* theme param handled below */

  window.setMode = setMode;
  window.addEventListener('message', function(e) {
    if (e.data && e.data.type === 'setMode') setMode(e.data.dark);
  });

  /* ── URL param: ?theme=dark|light sets initial mode ── */
  (function() {
    var href = window.location.href;
    setMode(href.indexOf('theme=dark') !== -1);
  })();

})();
//
